      chat.flow = null;
      cxAssistantPush027A(chat, "assistant", `Stock actualizado: ${cxAssistantInventoryLabel027W(updated)}.`);
      cxAssistantRefreshStockView028A();
      await cxAssistantPushStockSummary028A(chat, "stock", { intro: false });
