  function cxSlProMoney026L(value, currency = "COP") {
    return cxShoplinkMoney026K(value, currency);
  }

  async function cxSlProLoad026L() {
    if (!state.companyId) throw new Error("No hay empresa activa.");
    return api(`/shoplink/companies/${encodeURIComponent(state.companyId)}/products`);
  }

  function cxSlProCategoryOptions026L(categories = [], selected = "") {
    const list = Array.isArray(categories) && categories.length ? categories : ["General"];
    const current = selected || list[0] || "General";
    const final = list.includes(current) ? list : [current, ...list];
    return final.map((category) => `<option value="${h(category)}" ${category === current ? "selected" : ""}>${h(category)}</option>`).join("");
  }

  function cxSlProInventoryOptions026L(items = [], selected = "") {
    return [
      `<option value="">Sin enlace</option>`,
      ...items.map((item) => {
        const label = [item.name, item.sku, item.size, item.color].filter(Boolean).join(" / ");
        return `<option value="${h(item.id)}" ${String(item.id) === String(selected) ? "selected" : ""}>${h(label || item.id)} - stock ${h(item.stock || 0)}</option>`;
      })
    ].join("");
  }

  function cxSlProImageUrls026L(value = "") {
    return cxShoplinkSplit026K(value).slice(0, 3);
  }

  function cxSlProImageUrlInputs026L() {
    return [1, 2, 3].map((index) => String($(`slProImageUrl${index}026L`)?.value || "").trim()).filter(Boolean).slice(0, 3);
  }

  function cxSlProImageFiles026L() {
    return [1, 2, 3].flatMap((index) => Array.from($(`slProImageFile${index}026L`)?.files || [])).slice(0, 3);
  }

  function cxSlProExternalImageUrls026L(product = {}) {
    const urls = Array.isArray(product.image_urls) && product.image_urls.length
      ? product.image_urls
      : [product.image_url].filter(Boolean);
    return urls
      .filter((url) => url && !String(url).includes("/api/v1/shoplink/products/"))
      .slice(0, 3);
  }

  function cxSlProFilteredProducts026L(payload = {}) {
    const products = Array.isArray(payload.products) ? payload.products : [];
    const query = cxNormShoplink026K(cxSlProSearch026L);
    if (!query) return products;
    return products.filter((product) => cxNormShoplink026K([
      product.name,
      product.sku,
      product.category,
      product.size,
      product.color,
      product.price,
      product.status,
    ].filter(Boolean).join(" ")).includes(query));
  }

  function cxSlProProductList026L(payload = {}) {
    const products = cxSlProFilteredProducts026L(payload);
    const currency = payload.settings?.currency || "COP";
    if (!products.length) {
      return `<div class="slpro-empty-026l"><strong>Sin articulos</strong><p class="client-muted">Agrega el primer articulo o cambia el filtro de busqueda.</p></div>`;
    }
    return products.map((product) => `
      <article class="slpro-list-row-026l ${product.archived ? "archived" : ""}">
        <div>
          <strong>${h(product.name || "Articulo")}</strong>
          <small>${h(product.category || "General")} · ${product.published && !product.archived ? "Publicado" : product.archived ? "Archivado" : "Oculto"}</small>
        </div>
        <div>
          <strong>${h(product.sku || "Sin SKU")}</strong>
          <small>${h([product.size, product.color].filter(Boolean).join(" / ") || "Sin variante")}</small>
        </div>
        <div>
          <strong>${h(cxSlProMoney026L(product.price, currency))}</strong>
          <small>Stock ${h(product.stock || 0)} · Fotos ${h((product.image_urls || []).length || (product.image_url ? 1 : 0))}</small>
        </div>
        <div class="slpro-row-actions-026l">
          <button class="slpro-mini-btn-026l" type="button" data-slpro-edit="${h(product.id)}">Editar</button>
          ${(!product.published || product.archived) ? `<button class="slpro-mini-btn-026l ok" type="button" data-slpro-enable="${h(product.id)}">Habilitar</button>` : ""}
          ${!product.archived ? `<button class="slpro-mini-btn-026l" type="button" data-slpro-archive="${h(product.id)}">Archivar</button>` : ""}
          <button class="slpro-mini-btn-026l danger" type="button" data-slpro-delete="${h(product.id)}">Eliminar</button>
        </div>
      </article>
    `).join("");
  }

  function cxSlProFillForm026L(product = {}) {
    cxSlProCurrentProduct026L = product.id || "";
    const set = (id, value) => {
      const el = document.getElementById(id);
      if (el) el.value = value ?? "";
    };
    set("slProName026L", product.name || "");
    set("slProSku026L", product.sku || "");
    set("slProPrice026L", product.price || "");
    set("slProStock026L", product.stock || "");
    set("slProSize026L", product.size || "");
    set("slProColor026L", product.color || "");
    set("slProDescription026L", product.description || "");
    const externalUrls = cxSlProExternalImageUrls026L(product);
    [1, 2, 3].forEach((index) => set(`slProImageUrl${index}026L`, externalUrls[index - 1] || ""));
    set("slProInventory026L", product.inventory_item_id || "");
    const category = document.getElementById("slProCategory026L");
    if (category) category.value = product.category || category.options?.[0]?.value || "General";
    const published = document.getElementById("slProPublished026L");
    const archived = document.getElementById("slProArchived026L");
    const featured = document.getElementById("slProFeatured026L");
    if (published) published.checked = product.published !== false;
    if (archived) archived.checked = Boolean(product.archived);
    if (featured) featured.checked = Boolean(product.featured);
    [1, 2, 3].forEach((index) => {
      const file = document.getElementById(`slProImageFile${index}026L`);
      if (file) file.value = "";
    });
    cxSlProMessage026L(product.id ? "Editando producto existente." : "");
  }

  function cxSlProReadPayload026L() {
    return {
      name: $("slProName026L")?.value || "",
      category: $("slProCategory026L")?.value || "General",
      sku: $("slProSku026L")?.value || "",
      price: Number($("slProPrice026L")?.value || 0),
      stock: Number($("slProStock026L")?.value || 0),
      size: $("slProSize026L")?.value || "",
      color: $("slProColor026L")?.value || "",
      description: $("slProDescription026L")?.value || "",
      image_url: cxSlProImageUrlInputs026L()[0] || "",
      image_urls: cxSlProImageUrlInputs026L(),
      inventory_item_id: $("slProInventory026L")?.value || "",
      published: !!$("slProPublished026L")?.checked,
      archived: !!$("slProArchived026L")?.checked,
      featured: !!$("slProFeatured026L")?.checked,
    };
  }

  function cxSlProMessage026L(text, isError = false) {
    const el = $("slProMsg026L");
    if (!el) return;
    el.textContent = text || "";
    el.style.color = isError ? "#ff7aa8" : "var(--accent)";
  }

